        limit_req zone=cf_crawlers burst=5 nodelay;
        try_files $uri $rocket_root_cache $rocket_cache_file $uri/ /index.php?$args;
    }

    # WordPress Multisite subdirectory rewrites
    if (!-e $request_filename) {
        rewrite /wp-admin$ $scheme://$host$uri/ permanent;
        rewrite ^(/[^/]+)?(/wp-.*) $2 last;
        rewrite ^(/[^/]+)?(/.*\.php) $2 last;
    }
    # Uploads do blog principal: arquivo nao encontrado retorna 404 puro,
    # nunca cai no PHP (evita WP renderizar archive.php em URLs malformadas).
    location ^~ /wp-content/uploads/ {
        expires 1y;
        add_header Cache-Control "public, immutable";
        try_files $uri =404;
    }

    # Static files caching - Configurações controladas por variáveis
    location ~* \.(?:js|css|png|jpg|jpeg|gif|svg|woff2?|ttf|eot)$ {
        expires 1y;
--
    }

    # TEC day-view: redirect crawlers para /eventos/ (colapsa superfície infinita de datas)
    # Multisite: (/[^/]+)? captura prefixo de subsite como /cultura/
    location ~ "^(/[^/]+)?/eventos/\d{4}-\d{2}-\d{2}" {
        limit_req zone=cf_crawlers burst=2 nodelay;
        if ($rocket_is_logged_in = 0) {
            return 301 $1/eventos/;
        }
        try_files $uri $uri/ /index.php?$args;
    }

    # TEC REST API: rate limit + timeout curto (sem uso público)
    # Usa rewrite+break (não try_files) para que fastcgi_read_timeout 15 se aplique aqui
    location ~ ^/wp-json/tribe {
        limit_req zone=cf_crawlers burst=2 nodelay;
        rewrite ^ /index.php?$args break;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 15;
        fastcgi_send_timeout 15;
    }

    # Security restrictions
    location ~ /\.ht { deny all; }
    location ~* /(?:wp-config\.php|readme\.html|license\.txt)$ { deny all; }

    # ==== Hardening: rate limiting e bloqueios ====

    # wp-login.php: rate limit anti-brute-force (5 req/min, burst=3)
    location = /wp-login.php {
        limit_req zone=wp_login burst=3 nodelay;
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;

